INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-d0d1b9a2-moex-00264', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲大學設有文書處理室，主要協助文件的印刷。該處室有2個主要的使用者：商學院和文學 院。文書處理室年度預算資料摘要如下： 每年固定成本 $60,000 每張印刷的變動成本 $0.05 商學院預計使用量 120,000張 文學院預計使用量 240,000張 商學院實際使用量 80,000張 文學院實際使用量 200,000張 該大學是用預計使用量分攤固定印刷成本，且用實際使用量分攤變動成本。若採用雙重分攤 率來分攤成本，則文學院應分攤的文書處理室成本金額為何？', '["$40,000", "$50,000", "$52,000", "$52,857"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00265', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司採分步成本制度，產品製造需先經過A部門，至B部門完工後才可供銷售。B部門於 完工程度50%處設置檢驗點，期初無在製品存貨，本月完工轉出的完好品有2,000單位，期 末在製品有500單位（完工程度60%）。B部門本月份相關資料如下： 完工並轉出之完好產品成本 $100,000 正常損壞成本 $20,000 異常損壞成本 $6,000 期末在製品成本 $24,000 本期投入之總成本 $150,000 依據上述資料將B部門成本轉出至製成品，下列何者為認列相關損壞之分錄？', '["借記：製成品126,000；貸記：在製品－B部門126,000", "借記：製成品100,000，借記：異常損壞損失26,000；貸記：在製品－B部門126,000", "借記：製成品116,000，借記：製造費用6,000；貸記：在製品－B部門122,000", "借記：製成品116,000，借記：異常損壞損失6,000；貸記：在製品－B部門122,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00266', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '有關分步成本制之敘述，下列何者正確？', '["分步成本制適用於具有獨特性且大量生產的產品", "工程顧問公司包含水利、水保、土木、大地、結構、環境工程、景觀工程、事務管理等專 業，最適合採用分步成本制", "在分步成本制下，當計算部門轉出成本時，如沒有期初存貨時，採用加權平均法與採用先 進先出法的計算結果並無差異", "在完工程度60%處設置檢查點，若該公司期末在製品存貨之完工程度為80%，則有關正常 損壞及非常損壞皆應計入當期完工產品的成本之中"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00267', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司採分批成本制，去年將多分攤或少分攤的製造費用依比率攤到在製品、製成品與銷貨 成本帳戶貸方之金額分別為$1,000、$1,500與$2,500。該公司去年發生費用如下： 間接材料 $ 10,000 間接人工 20,000 其他製造費用 100,000 銷售與管理費用 50,000 總間接成本 $180,000 下列何者為該公司去年度已分攤製造費用？', '["$125,000", "$135,000", "$175,000", "$185,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00268', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司生產505批號產品5,000單位，其單位成本如下：直接材料$21，直接人工$10，製造 費用$9。生產完成後，發現有100單位為正常損壞品（該批次客戶採用較嚴格品管標準所致）， 其並無任何銷售價值，下列何者為正確之會計處理？', '["借︰在製品4,000", "借︰製造費用4,000", "借︰正常損失4,000", "無須作分錄"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00269', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司有A、B兩個部門，採部門別製造費用分攤率，且製造費用係依直接人工成本基礎分 攤。相關資訊如下： A部門：預計直接人工成本$200,000，預計製造費用$600,000。 B部門：預計直接人工成本$40,000，預計製造費用$80,000。 訂單#475發生之實際直接成本為：直接原料$25,000，直接人工成本$20,000（A部門$8,000及 B部門$12,000）。下列何者為訂單#475之製成品成本？', '["$30,000", "$50,000", "$75,000", "$93,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00270', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司生產銅箔基板，採標準成本制，3月份預計生產300單位。購入化工原料6,000公斤， 實際生產250單位，所允許的標準用量為5,400公斤，實際用量5,800公斤，其標準單價與實 際單價分別為$30及$27。有關3月份之原料成本差異分析，下列何者正確？', '["數量差異為不利$10,800", "數量差異為不利$12,000", "購料價格差異為有利$16,200", "用料價格差異為有利$18,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00271', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司生產單一產品，每單位產品必須投入5單位之原料，每單位原料購價為$3，X1年期初 原料存貨有5,000單位。甲公司預計X1年生產9,000單位產品，且預計降低原料期末存貨水 準至期初存貨的80%。下列何者為X1年原料採購成本預算？', '["$135,000", "$132,000", "$123,000", "$120,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00272', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '關於銷貨毛利差異分析之敘述，下列何者錯誤？', '["銷貨毛利價格差異＝售價差異＋原料價格差異", "銷貨毛利差異＝銷貨毛利價格差異＋銷貨毛利數量差異", "銷貨毛利數量差異＝銷售組合差異＋純粹銷售數量差異", "銷貨毛利數量差異＝銷售組合差異＋市場需求差異＋市場占有率差異"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00273', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司產銷芒果乾，於攸關區間營運，產銷量為 35,000 公斤時，銷貨收入為$1,050,000，銷 管費用為$775,000，營業淨利為$275,000；產品的產銷量為 45,000 公斤時，銷貨收入為 $1,350,000，銷管費用為$925,000，營業淨利為$425,000。下列何者為產品的邊際貢獻率（四 捨五入至整數位）？', '["21%", "50%", "69%", "71%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL)
